const idea = $.input.videoIdea || '';
const query = 'cinematic video techniques AI generation ' + idea.split(' ').slice(0, 4).join(' ');
return { query };

const idea = $.input.videoIdea;
const length = $.input.videoLength || '8';
const results = $.steps.researchStyles.response.results || [];
let refs = '';
results.forEach((r, i) => { refs += (i + 1) + '. ' + (r.title || '') + ': ' + (r.text || '').slice(0, 150) + '
'; });

const prompt = 'You are a cinematic AI video prompt engineer. Transform a simple video idea into a detailed, optimized prompt for AI video generation (VEO3/Sora-style models).

ORIGINAL IDEA: ' + idea + '
TARGET LENGTH: ' + length + ' seconds

CINEMATOGRAPHY RESEARCH:
' + refs + '

Return ONLY valid JSON:
{
  "originalIdea": "the input idea",
  "optimizedPrompt": "detailed cinematic prompt with camera angles, lighting, movement, textures, atmosphere - 2-3 sentences",
  "negativePrompt": "what to avoid in generation",
  "stylePreset": "cinematic/documentary/abstract/commercial/music-video",
  "cameraMovement": "dolly/pan/tilt/crane/steadicam/drone/static",
  "lightingSetup": "golden hour/studio/natural/neon/dramatic",
  "colorGrading": "warm/cool/desaturated/vivid/filmic",
  "fps": 24,
  "resolution": "1080p/4K",
  "aspectRatio": "16:9/9:16/1:1",
  "audioDescription": "native audio or ambient sound description",
  "alternativePrompts": ["variation 1", "variation 2"],
  "qualityScore": "estimated quality improvement from original 1-10"
}';

return { prompt };

let raw = $.steps.aiOptimize.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { optimizedPrompt: raw, stylePreset: 'cinematic' }; }

const ai = $.steps.parseAI.output;
let doc = 'AI VIDEO SPECIFICATION\n';
doc += '=====================\n\n';
doc += 'Date: ' + new Date().toISOString().split('T')[0] + '\n';
doc += 'Original Idea: ' + $.input.videoIdea + '\n';
doc += 'Target Length: ' + $.input.videoLength + 's\n\n';
doc += 'OPTIMIZED PROMPT\n';
doc += '----------------\n';
doc += (ai.optimizedPrompt || '') + '\n\n';
if (ai.negativePrompt) { doc += 'Negative Prompt: ' + ai.negativePrompt + '\n\n'; }
doc += 'TECHNICAL SPECS\n';
doc += '---------------\n';
doc += 'Style: ' + (ai.stylePreset || '') + '\n';
doc += 'Camera: ' + (ai.cameraMovement || '') + '\n';
doc += 'Lighting: ' + (ai.lightingSetup || '') + '\n';
doc += 'Color: ' + (ai.colorGrading || '') + '\n';
doc += 'FPS: ' + (ai.fps || 24) + '\n';
doc += 'Resolution: ' + (ai.resolution || '1080p') + '\n';
doc += 'Aspect Ratio: ' + (ai.aspectRatio || '16:9') + '\n';
if (ai.audioDescription) { doc += 'Audio: ' + ai.audioDescription + '\n'; }
if (ai.alternativePrompts && ai.alternativePrompts.length > 0) {
  doc += '\nALTERNATIVE PROMPTS\n';
  ai.alternativePrompts.forEach((p, i) => { doc += (i + 1) + '. ' + p + '\n'; });
}
doc += '\nQuality Score: ' + (ai.qualityScore || 'N/A') + '/10';
const title = 'Video Spec - ' + $.input.videoIdea.slice(0, 40);
const slackText = 'Video spec ready: "' + $.input.videoIdea.slice(0, 50) + '" | ' + (ai.stylePreset || '') + ' | ' + (ai.cameraMovement || '') + ' | Quality: ' + (ai.qualityScore || 'N/A') + '/10';
return { doc, title, slackText };
